3922 std::optional<CmpPredicate> CmpPredicate::getMatching(CmpPredicate A,
3923                                                       CmpPredicate B) {
3924   if (A.Pred == B.Pred)
3925     return A.HasSameSign == B.HasSameSign ? A : CmpPredicate(A.Pred);
3926   if (A.HasSameSign &&
3927       A.Pred == ICmpInst::getFlippedSignednessPredicate(B.Pred))
3928     return B.Pred;
3929   if (B.HasSameSign &&
3930       B.Pred == ICmpInst::getFlippedSignednessPredicate(A.Pred))
3931     return A.Pred;
3932   return {};
3933 }
