9388 /// Return true if "icmp LPred X, LCR" implies "icmp RPred X, RCR" is true.
9389 /// Return false if "icmp LPred X, LCR" implies "icmp RPred X, RCR" is false.
9390 /// Otherwise, return std::nullopt if we can't infer anything.
9391 static std::optional<bool>
9392 isImpliedCondCommonOperandWithCR(CmpPredicate LPred, const ConstantRange &LCR,
9393                                  CmpPredicate RPred, const ConstantRange &RCR) {
9394   auto CRImpliesPred = [&](ConstantRange CR,
9395                            CmpInst::Predicate Pred) -> std::optional<bool> {
9396     // If all true values for lhs and true for rhs, lhs implies rhs
9397     if (CR.icmp(Pred, RCR))
9398       return true;
9399 
9400     // If there is no overlap, lhs implies not rhs
9401     if (CR.icmp(CmpInst::getInversePredicate(Pred), RCR))
9402       return false;
9403 
9404     return std::nullopt;
9405   };
9406   if (auto Res = CRImpliesPred(ConstantRange::makeAllowedICmpRegion(LPred, LCR),
9407                                RPred))
9408     return Res;
9409   if (LPred.hasSameSign() ^ RPred.hasSameSign()) {
9410     LPred = LPred.hasSameSign() ? ICmpInst::getFlippedSignednessPredicate(LPred)
9411                                 : static_cast<CmpInst::Predicate>(LPred);
9412     RPred = RPred.hasSameSign() ? ICmpInst::getFlippedSignednessPredicate(RPred)
9413                                 : static_cast<CmpInst::Predicate>(RPred);
9414     return CRImpliesPred(ConstantRange::makeAllowedICmpRegion(LPred, LCR),
9415                          RPred);
9416   }
9417   return std::nullopt;
9418 }
9419 
9420 /// Return true if LHS implies RHS (expanded to its components as "R0 RPred R1")
9421 /// is true.  Return false if LHS implies RHS is false. Otherwise, return
9422 /// std::nullopt if we can't infer anything.
9423 static std::optional<bool>
9424 isImpliedCondICmps(const ICmpInst *LHS, CmpPredicate RPred, const Value *R0,
9425                    const Value *R1, const DataLayout &DL, bool LHSIsTrue) {
9426   Value *L0 = LHS->getOperand(0);
9427   Value *L1 = LHS->getOperand(1);
9428 
9429   // The rest of the logic assumes the LHS condition is true.  If that's not the
9430   // case, invert the predicate to make it so.
9431   CmpPredicate LPred =
9432       LHSIsTrue ? LHS->getCmpPredicate() : LHS->getInverseCmpPredicate();
9433 
9434   // We can have non-canonical operands, so try to normalize any common operand
9435   // to L0/R0.
9436   if (L0 == R1) {
9437     std::swap(R0, R1);
9438     RPred = ICmpInst::getSwappedCmpPredicate(RPred);
9439   }
9440   if (R0 == L1) {
9441     std::swap(L0, L1);
9442     LPred = ICmpInst::getSwappedCmpPredicate(LPred);
9443   }
9444   if (L1 == R1) {
9445     // If we have L0 == R0 and L1 == R1, then make L1/R1 the constants.
9446     if (L0 != R0 || match(L0, m_ImmConstant())) {
9447       std::swap(L0, L1);
9448       LPred = ICmpInst::getSwappedCmpPredicate(LPred);
9449       std::swap(R0, R1);
9450       RPred = ICmpInst::getSwappedCmpPredicate(RPred);
9451     }
9452   }
9453 
9454   // See if we can infer anything if operand-0 matches and we have at least one
9455   // constant.
9456   const APInt *Unused;
9457   if (L0 == R0 && (match(L1, m_APInt(Unused)) || match(R1, m_APInt(Unused)))) {
9458     // Potential TODO: We could also further use the constant range of L0/R0 to
9459     // further constraint the constant ranges. At the moment this leads to
9460     // several regressions related to not transforming `multi_use(A + C0) eq/ne
9461     // C1` (see discussion: D58633).
9462     ConstantRange LCR = computeConstantRange(
9463         L1, ICmpInst::isSigned(LPred), /* UseInstrInfo=*/true, /*AC=*/nullptr,
9464         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9465     ConstantRange RCR = computeConstantRange(
9466         R1, ICmpInst::isSigned(RPred), /* UseInstrInfo=*/true, /*AC=*/nullptr,
9467         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9468     // Even if L1/R1 are not both constant, we can still sometimes deduce
9469     // relationship from a single constant. For example X u> Y implies X != 0.
9470     if (auto R = isImpliedCondCommonOperandWithCR(LPred, LCR, RPred, RCR))
9471       return R;
9472     // If both L1/R1 were exact constant ranges and we didn't get anything
9473     // here, we won't be able to deduce this.
9474     if (match(L1, m_APInt(Unused)) && match(R1, m_APInt(Unused)))
9475       return std::nullopt;
9476   }
9477 
9478   // Can we infer anything when the two compares have matching operands?
9479   if (L0 == R0 && L1 == R1)
9480     return isImpliedCondMatchingOperands(LPred, RPred);
9481 
9482   // It only really makes sense in the context of signed comparison for "X - Y
9483   // must be positive if X >= Y and no overflow".
9484   // Take SGT as an example:  L0:x > L1:y and C >= 0
9485   //                      ==> R0:(x -nsw y) < R1:(-C) is false
9486   if ((LPred == ICmpInst::ICMP_SGT || LPred == ICmpInst::ICMP_SGE) &&
9487       match(R0, m_NSWSub(m_Specific(L0), m_Specific(L1)))) {
9488     if (match(R1, m_NonPositive()) &&
9489         isImpliedCondMatchingOperands(LPred, RPred) == false)
9490       return false;
9491   }
9492 
9493   // Take SLT as an example:  L0:x < L1:y and C <= 0
9494   //                      ==> R0:(x -nsw y) < R1:(-C) is true
9495   if ((LPred == ICmpInst::ICMP_SLT || LPred == ICmpInst::ICMP_SLE) &&
9496       match(R0, m_NSWSub(m_Specific(L0), m_Specific(L1)))) {
9497     if (match(R1, m_NonNegative()) &&
9498         isImpliedCondMatchingOperands(LPred, RPred) == true)
9499       return true;
9500   }
9501 
9502   // L0 = R0 = L1 + R1, L0 >=u L1 implies R0 >=u R1, L0 <u L1 implies R0 <u R1
9503   if (L0 == R0 &&
9504       (LPred == ICmpInst::ICMP_ULT || LPred == ICmpInst::ICMP_UGE) &&
9505       (RPred == ICmpInst::ICMP_ULT || RPred == ICmpInst::ICMP_UGE) &&
9506       match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))))
9507     return CmpPredicate::getMatching(LPred, RPred).has_value();
9508 
9509   if (auto P = CmpPredicate::getMatching(LPred, RPred))
9510     return isImpliedCondOperands(*P, L0, L1, R0, R1);
9511 
9512   return std::nullopt;
9513 }
9514 
9515 /// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
9516 /// false.  Otherwise, return std::nullopt if we can't infer anything.  We
9517 /// expect the RHS to be an icmp and the LHS to be an 'and', 'or', or a 'select'
9518 /// instruction.
9519 static std::optional<bool>
9520 isImpliedCondAndOr(const Instruction *LHS, CmpPredicate RHSPred,
9521                    const Value *RHSOp0, const Value *RHSOp1,
9522                    const DataLayout &DL, bool LHSIsTrue, unsigned Depth) {
9523   // The LHS must be an 'or', 'and', or a 'select' instruction.
9524   assert((LHS->getOpcode() == Instruction::And ||
9525           LHS->getOpcode() == Instruction::Or ||
9526           LHS->getOpcode() == Instruction::Select) &&
9527          "Expected LHS to be 'and', 'or', or 'select'.");
9528 
9529   assert(Depth <= MaxAnalysisRecursionDepth && "Hit recursion limit");
9530 
9531   // If the result of an 'or' is false, then we know both legs of the 'or' are
9532   // false.  Similarly, if the result of an 'and' is true, then we know both
9533   // legs of the 'and' are true.
9534   const Value *ALHS, *ARHS;
9535   if ((!LHSIsTrue && match(LHS, m_LogicalOr(m_Value(ALHS), m_Value(ARHS)))) ||
9536       (LHSIsTrue && match(LHS, m_LogicalAnd(m_Value(ALHS), m_Value(ARHS))))) {
9537     // FIXME: Make this non-recursion.
9538     if (std::optional<bool> Implication = isImpliedCondition(
9539             ALHS, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue, Depth + 1))
9540       return Implication;
9541     if (std::optional<bool> Implication = isImpliedCondition(
9542             ARHS, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue, Depth + 1))
9543       return Implication;
9544     return std::nullopt;
9545   }
9546   return std::nullopt;
9547 }
9548 
9549 std::optional<bool>
9550 llvm::isImpliedCondition(const Value *LHS, CmpPredicate RHSPred,
9551                          const Value *RHSOp0, const Value *RHSOp1,
9552                          const DataLayout &DL, bool LHSIsTrue, unsigned Depth) {
9553   // Bail out when we hit the limit.
9554   if (Depth == MaxAnalysisRecursionDepth)
9555     return std::nullopt;
9556 
9557   // A mismatch occurs when we compare a scalar cmp to a vector cmp, for
9558   // example.
9559   if (RHSOp0->getType()->isVectorTy() != LHS->getType()->isVectorTy())
9560     return std::nullopt;
9561 
9562   assert(LHS->getType()->isIntOrIntVectorTy(1) &&
9563          "Expected integer type only!");
9564 
9565   // Match not
9566   if (match(LHS, m_Not(m_Value(LHS))))
9567     LHSIsTrue = !LHSIsTrue;
9568 
9569   // Both LHS and RHS are icmps.
9570   const ICmpInst *LHSCmp = dyn_cast<ICmpInst>(LHS);
9571   if (LHSCmp)
9572     return isImpliedCondICmps(LHSCmp, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue);
9573 
9574   /// The LHS should be an 'or', 'and', or a 'select' instruction.  We expect
9575   /// the RHS to be an icmp.
9576   /// FIXME: Add support for and/or/select on the RHS.
9577   if (const Instruction *LHSI = dyn_cast<Instruction>(LHS)) {
9578     if ((LHSI->getOpcode() == Instruction::And ||
9579          LHSI->getOpcode() == Instruction::Or ||
9580          LHSI->getOpcode() == Instruction::Select))
9581       return isImpliedCondAndOr(LHSI, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue,
9582                                 Depth);
9583   }
9584   return std::nullopt;
9585 }
9586 
9587 std::optional<bool> llvm::isImpliedCondition(const Value *LHS, const Value *RHS,
9588                                              const DataLayout &DL,
9589                                              bool LHSIsTrue, unsigned Depth) {
9590   // LHS ==> RHS by definition
9591   if (LHS == RHS)
9592     return LHSIsTrue;
9593 
9594   // Match not
9595   bool InvertRHS = false;
9596   if (match(RHS, m_Not(m_Value(RHS)))) {
9597     if (LHS == RHS)
9598       return !LHSIsTrue;
9599     InvertRHS = true;
9600   }
9601 
9602   if (const ICmpInst *RHSCmp = dyn_cast<ICmpInst>(RHS)) {
9603     if (auto Implied = isImpliedCondition(
9604             LHS, RHSCmp->getCmpPredicate(), RHSCmp->getOperand(0),
9605             RHSCmp->getOperand(1), DL, LHSIsTrue, Depth))
9606       return InvertRHS ? !*Implied : *Implied;
9607     return std::nullopt;
9608   }
9609 
9610   if (Depth == MaxAnalysisRecursionDepth)
9611     return std::nullopt;
9612 
9613   // LHS ==> (RHS1 || RHS2) if LHS ==> RHS1 or LHS ==> RHS2
9614   // LHS ==> !(RHS1 && RHS2) if LHS ==> !RHS1 or LHS ==> !RHS2
9615   const Value *RHS1, *RHS2;
9616   if (match(RHS, m_LogicalOr(m_Value(RHS1), m_Value(RHS2)))) {
9617     if (std::optional<bool> Imp =
9618             isImpliedCondition(LHS, RHS1, DL, LHSIsTrue, Depth + 1))
9619       if (*Imp == true)
9620         return !InvertRHS;
9621     if (std::optional<bool> Imp =
9622             isImpliedCondition(LHS, RHS2, DL, LHSIsTrue, Depth + 1))
9623       if (*Imp == true)
9624         return !InvertRHS;
9625   }
9626   if (match(RHS, m_LogicalAnd(m_Value(RHS1), m_Value(RHS2)))) {
9627     if (std::optional<bool> Imp =
9628             isImpliedCondition(LHS, RHS1, DL, LHSIsTrue, Depth + 1))
9629       if (*Imp == false)
9630         return InvertRHS;
9631     if (std::optional<bool> Imp =
9632             isImpliedCondition(LHS, RHS2, DL, LHSIsTrue, Depth + 1))
9633       if (*Imp == false)
9634         return InvertRHS;
9635   }
9636 
9637   return std::nullopt;
