10062 ConstantRange llvm::computeConstantRange(const Value *V, bool ForSigned,
10063                                          bool UseInstrInfo, AssumptionCache *AC,
10064                                          const Instruction *CtxI,
10065                                          const DominatorTree *DT,
10066                                          unsigned Depth) {
10067   assert(V->getType()->isIntOrIntVectorTy() && "Expected integer instruction");
10068 
10069   if (Depth == MaxAnalysisRecursionDepth)
10070     return ConstantRange::getFull(V->getType()->getScalarSizeInBits());
10071 
10072   if (auto *C = dyn_cast<Constant>(V))
10073     return C->toConstantRange();
10074 
10075   unsigned BitWidth = V->getType()->getScalarSizeInBits();
10076   InstrInfoQuery IIQ(UseInstrInfo);
10077   ConstantRange CR = ConstantRange::getFull(BitWidth);
10078   if (auto *BO = dyn_cast<BinaryOperator>(V)) {
10079     APInt Lower = APInt(BitWidth, 0);
10080     APInt Upper = APInt(BitWidth, 0);
10081     // TODO: Return ConstantRange.
10082     setLimitsForBinOp(*BO, Lower, Upper, IIQ, ForSigned);
10083     CR = ConstantRange::getNonEmpty(Lower, Upper);
10084   } else if (auto *II = dyn_cast<IntrinsicInst>(V))
10085     CR = getRangeForIntrinsic(*II);
10086   else if (auto *SI = dyn_cast<SelectInst>(V)) {
10087     ConstantRange CRTrue = computeConstantRange(
10088         SI->getTrueValue(), ForSigned, UseInstrInfo, AC, CtxI, DT, Depth + 1);
10089     ConstantRange CRFalse = computeConstantRange(
10090         SI->getFalseValue(), ForSigned, UseInstrInfo, AC, CtxI, DT, Depth + 1);
10091     CR = CRTrue.unionWith(CRFalse);
10092     CR = CR.intersectWith(getRangeForSelectPattern(*SI, IIQ));
10093   } else if (isa<FPToUIInst>(V) || isa<FPToSIInst>(V)) {
10094     APInt Lower = APInt(BitWidth, 0);
10095     APInt Upper = APInt(BitWidth, 0);
10096     // TODO: Return ConstantRange.
10097     setLimitForFPToI(cast<Instruction>(V), Lower, Upper);
10098     CR = ConstantRange::getNonEmpty(Lower, Upper);
10099   } else if (const auto *A = dyn_cast<Argument>(V))
10100     if (std::optional<ConstantRange> Range = A->getRange())
10101       CR = *Range;
10102 
10103   if (auto *I = dyn_cast<Instruction>(V)) {
10104     if (auto *Range = IIQ.getMetadata(I, LLVMContext::MD_range))
10105       CR = CR.intersectWith(getConstantRangeFromMetadata(*Range));
10106 
10107     if (const auto *CB = dyn_cast<CallBase>(V))
10108       if (std::optional<ConstantRange> Range = CB->getRange())
10109         CR = CR.intersectWith(*Range);
10110   }
