10142 static void
10143 addValueAffectedByCondition(Value *V,
10144                             function_ref<void(Value *)> InsertAffected) {
10145   assert(V != nullptr);
10146   if (isa<Argument>(V) || isa<GlobalValue>(V)) {
10147     InsertAffected(V);
10148   } else if (auto *I = dyn_cast<Instruction>(V)) {
10149     InsertAffected(V);
10150 
10151     // Peek through unary operators to find the source of the condition.
10152     Value *Op;
10153     if (match(I, m_CombineOr(m_PtrToInt(m_Value(Op)), m_Trunc(m_Value(Op))))) {
10154       if (isa<Instruction>(Op) || isa<Argument>(Op))
10155         InsertAffected(Op);
10156     }
10157   }
10158 }
