10160 void llvm::findValuesAffectedByCondition(
10161     Value *Cond, bool IsAssume, function_ref<void(Value *)> InsertAffected) {
10162   auto AddAffected = [&InsertAffected](Value *V) {
10163     addValueAffectedByCondition(V, InsertAffected);
10164   };
10165 
10166   auto AddCmpOperands = [&AddAffected, IsAssume](Value *LHS, Value *RHS) {
10167     if (IsAssume) {
10168       AddAffected(LHS);
10169       AddAffected(RHS);
10170     } else if (match(RHS, m_Constant()))
10171       AddAffected(LHS);
10172   };
10173 
10174   SmallVector<Value *, 8> Worklist;
10175   SmallPtrSet<Value *, 8> Visited;
10176   Worklist.push_back(Cond);
10177   while (!Worklist.empty()) {
10178     Value *V = Worklist.pop_back_val();
10179     if (!Visited.insert(V).second)
10180       continue;
10181 
10182     CmpPredicate Pred;
10183     Value *A, *B, *X;
10184 
10185     if (IsAssume) {
10186       AddAffected(V);
10187       if (match(V, m_Not(m_Value(X))))
10188         AddAffected(X);
10189     }
10190 
10191     if (match(V, m_LogicalOp(m_Value(A), m_Value(B)))) {
10192       // assume(A && B) is split to -> assume(A); assume(B);
10193       // assume(!(A || B)) is split to -> assume(!A); assume(!B);
10194       // Finally, assume(A || B) / assume(!(A && B)) generally don't provide
10195       // enough information to be worth handling (intersection of information as
10196       // opposed to union).
10197       if (!IsAssume) {
10198         Worklist.push_back(A);
10199         Worklist.push_back(B);
10200       }
10201     } else if (match(V, m_ICmp(Pred, m_Value(A), m_Value(B)))) {
10202       AddCmpOperands(A, B);
10203 
10204       bool HasRHSC = match(B, m_ConstantInt());
10205       if (ICmpInst::isEquality(Pred)) {
10206         if (HasRHSC) {
10207           Value *Y;
10208           // (X & C) or (X | C) or (X ^ C).
10209           // (X << C) or (X >>_s C) or (X >>_u C).
10210           if (match(A, m_BitwiseLogic(m_Value(X), m_ConstantInt())) ||
10211               match(A, m_Shift(m_Value(X), m_ConstantInt())))
10212             AddAffected(X);
10213           else if (match(A, m_And(m_Value(X), m_Value(Y))) ||
10214                    match(A, m_Or(m_Value(X), m_Value(Y)))) {
10215             AddAffected(X);
10216             AddAffected(Y);
10217           }
10218         }
10219       } else {
10220         if (HasRHSC) {
10221           // Handle (A + C1) u< C2, which is the canonical form of
10222           // A > C3 && A < C4.
10223           if (match(A, m_AddLike(m_Value(X), m_ConstantInt())))
10224             AddAffected(X);
10225 
10226           if (ICmpInst::isUnsigned(Pred)) {
10227             Value *Y;
10228             // X & Y u> C    -> X >u C && Y >u C
10229             // X | Y u< C    -> X u< C && Y u< C
10230             // X nuw+ Y u< C -> X u< C && Y u< C
10231             if (match(A, m_And(m_Value(X), m_Value(Y))) ||
10232                 match(A, m_Or(m_Value(X), m_Value(Y))) ||
10233                 match(A, m_NUWAdd(m_Value(X), m_Value(Y)))) {
10234               AddAffected(X);
10235               AddAffected(Y);
10236             }
10237             // X nuw- Y u> C -> X u> C
10238             if (match(A, m_NUWSub(m_Value(X), m_Value())))
10239               AddAffected(X);
10240           }
10241         }
10242 
10243         // Handle icmp slt/sgt (bitcast X to int), 0/-1, which is supported
10244         // by computeKnownFPClass().
10245         if (match(A, m_ElementWiseBitCast(m_Value(X)))) {
10246           if (Pred == ICmpInst::ICMP_SLT && match(B, m_Zero()))
10247             InsertAffected(X);
10248           else if (Pred == ICmpInst::ICMP_SGT && match(B, m_AllOnes()))
10249             InsertAffected(X);
10250         }
10251       }
10252 
10253       if (HasRHSC && match(A, m_Intrinsic<Intrinsic::ctpop>(m_Value(X))))
10254         AddAffected(X);
10255     } else if (match(V, m_FCmp(Pred, m_Value(A), m_Value(B)))) {
10256       AddCmpOperands(A, B);
10257 
10258       // fcmp fneg(x), y
10259       // fcmp fabs(x), y
10260       // fcmp fneg(fabs(x)), y
10261       if (match(A, m_FNeg(m_Value(A))))
10262         AddAffected(A);
10263       if (match(A, m_FAbs(m_Value(A))))
10264         AddAffected(A);
10265 
10266     } else if (match(V, m_Intrinsic<Intrinsic::is_fpclass>(m_Value(A),
10267                                                            m_Value()))) {
10268       // Handle patterns that computeKnownFPClass() support.
10269       AddAffected(A);
10270     }
10271   }
10272 }
