9671 std::optional<bool> llvm::isImpliedByDomCondition(const Value *Cond,
9672                                                   const Instruction *ContextI,
9673                                                   const DataLayout &DL) {
9674   assert(Cond->getType()->isIntOrIntVectorTy(1) && "Condition must be bool");
9675   auto PredCond = getDomPredecessorCondition(ContextI);
